    public static function updateChainOnlineOrderRate($dataArray){

        $status = array();

        $chainID = $dataArray['chainID'];
        $rate    = $dataArray['rate'];

        $globalChainOnlineOrderRatesTable = Constants::getGlobalTableName("globalChainOnlineOrderRates");

        DB::transaction(function()use($globalChainOnlineOrderRatesTable, $chainID, $rate){

            DB::table($globalChainOnlineOrderRatesTable)->where('chainID', $chainID)->update(['rate' => $rate]);

       });

       $status['status'] = true;
       $status['message'] = "Chain ONLINE ORDER RATE Updated successfully";

       return $status;



    }

    public static function getStorePaymentSettings($dataArray){

        $status = array();

        $storeID = $dataArray['storeID'];

        $paymentSettingsTable = Constants::getTableName($storeID, "paymentSettings");
        $globalTypeValuesTable = Constants::getGlobalTableName("globalTypeValues");


        $paymentList = convertToArray(DB::select(DB::raw("SELECT A.ID, B.value, B.printName, A.isSystemIntegrated, A.isActive FROM $paymentSettingsTable AS A INNER JOIN $globalTypeValuesTable AS B ON A.paymentTypeID = B.ID WHERE B.isActive = 1 AND B.typeID = 7")));
        $newPaymentList = convertToArray(DB::select(DB::raw("SELECT ID AS paymentTypeID, printName, description FROM $globalTypeValuesTable WHERE isActive = 1 AND typeID = 7 AND ID NOT IN (SELECT DISTINCT paymentTypeID FROM $paymentSettingsTable);")));
        $status['status'] = true;
        $status['data'] = $paymentList;
        $status['newPaymentList'] = $newPaymentList;
        return $status;

    }

