        $storeID = $dataArray['storeID'];

        $isActive = 1;
		// paymentTypeID
        $paymentTypeID = $dataArray['paymentTypeID'];

		$getAccountDetails = convertToArray(DB::select(DB::raw("SELECT ID, value, printName FROM $globalTypeValuesTable WHERE ID IN (SELECT accountTypeValueID FROM $globalTypePaymentAccountIDMappingTable WHERE paymentTypeValueID = ?);"), [$paymentTypeID]));
		if (!isset($getAccountDetails) || !isset($getAccountDetails[0]) || !isset($getAccountDetails[0]["ID"]) || $getAccountDetails[0]["ID"] == null) {
			$status['status'] = false;
			$status['message'] = "Store payment setting cannot be added.";
			return $status;
		}

		$getChainID = convertToArray(DB::table($listOfStoresTable)->where("isActive", 1)->where("storeID", $storeID)->select("chainID")->get());
		if (!isset($getChainID) || !isset($getChainID[0]) || !isset($getChainID[0]["chainID"]) || $getChainID[0]["chainID"] == null) {
			$status['status'] = false;
			$status['message'] = "Chain not found or store inactive.";
			return $status;
		}
        $chainID = $getChainID[0]["chainID"];

		if ((env("WL_CHAINID") == null || env("WL_CHAINID") != $chainID) && $dataArray["source"] == "WEBV2") {
			// Check userID is present in request or not.
			if (!isset($dataArray["userID"]) || empty($dataArray["userID"])) {
				$status["status"] = false;
				$status["message"] = "User ID not present";

				return $status;
			}

			// check if user is SUPER_CHAIN_ADMIN
			$usersTable = Constants::getGlobalTableName("users");
			$userType = DB::table($usersTable)->where("ID", $dataArray["userID"])->value("userType");
			if ($userType != "SUPER_CHAIN_ADMIN") {
				$status["status"] = false;
				$status["message"] = "Payment settings can only be added by SUPER_CHAIN_ADMIN";

				return $status;
			}
		}

		$paymentSettingsTable = Constants::getTableName($storeID, "paymentSettings");
		$accountIDsTable = Constants::getChainTableName($chainID, "accountIDs");

		$accountArray = array();
		$accountArray["accountTypeValueID"] = $getAccountDetails[0]["ID"];
		$accountArray["accountName"] = str_replace("_RECD","", str_replace("ACC_","", $getAccountDetails[0]["value"])) . "Received";
		$storePaymentArray = array();
		$storePaymentArray["paymentTypeID"] = $paymentTypeID;
		$storePaymentArray["isSystemIntegrated"] = (isset($dataArray["isSystemIntegrated"]) && $dataArray["isSystemIntegrated"] == 1) ? 1 : 0;
		$storePaymentArray["isActive"] = 1;

        DB::transaction(function()use($accountIDsTable, $paymentSettingsTable, $accountArray, $storePaymentArray) {
			$checkChainAccount = convertToArray(DB::table($accountIDsTable)->where("accountTypeValueID", $accountArray["accountTypeValueID"])->get());
			if (empty($checkChainAccount)) {
				DB::table($accountIDsTable)->insert($accountArray);
			}
			$checkStorePayment = convertToArray(DB::table($paymentSettingsTable)->where("paymentTypeID", $storePaymentArray["paymentTypeID"])->get());
			if (empty($checkStorePayment)) {
				DB::table($paymentSettingsTable)->insert($storePaymentArray);
			} else {
				DB::table($paymentSettingsTable)->where('paymentTypeID', $storePaymentArray["paymentTypeID"])->update(['isActive' => 1]);
			}
       });

       $status['status'] = true;
       $status['message'] = "Store payment / Chain account  ".$getAccountDetails[0]["printName"]." added successfully";

       return $status;
    }

     public static function updateStorePaymentSettings($dataArray){

        $status = array();

        $storeID = $dataArray['storeID'];
        $isActive = $dataArray['isActive'];
        $paymentSettingsID = $dataArray['ID'];
		$listOfStoresTable = Constants::getGlobalTableName("listOfStores");

        $paymentSettingsTable = Constants::getTableName($storeID, "paymentSettings");

		$chainID = convertToArray(DB::table($listOfStoresTable)->where("storeID", $storeID)->select("chainID")->get());
