    public static function getDeviceSalesReport($dataArray, $thirdPartyChainID){

        $status = array();

        $fromDate = $dataArray['fromDate'];
        // format date to YYYY-MM-DD
        $fromDate = date("Y-m-d", strtotime($fromDate));
        $toDate = $dataArray['toDate'];
        // format date to YYYY-MM-DD
        $toDate = date("Y-m-d", strtotime($toDate));

        // reject if request is for more than 1 month
        $dateDiff = strtotime($toDate) - strtotime($fromDate);
        $dateDiff = $dateDiff / (60 * 60 * 24);
        if($dateDiff > 31){
            $status['status'] = false;
            $status['message'] = "Date range should be less than 31 days";
            return $status;
        }
        if($dateDiff < 0){
            $status['status'] = false;
            $status['message'] = "Invalid date range";
            return $status;
        }

        $globalCustomerOrderSummaryTable = Constants::getGlobalTableName("globalCustomerOrderSummary");
        $devicesInfoTable = Constants::getGlobalTableName("devicesInfo");
        $listOfStoresTable = Constants::getGlobalTableName("listOfStores");
        $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
        $thirdPartyRegionDeviceMapTable = Constants::getGlobalTableName("thirdPartyRegionDeviceMap");
        $globalQBFeaturePackagesTable = Constants::getGlobalTableName("globalQBFeaturePackages");
        $thirdPartyChainMapTable = Constants::getGlobalTableName("thirdPartyChainMap");

        $updatedQuery = "SELECT 
                agg.deviceID,
                B.deviceSerialNumber,
                B.modelNumber,
                B.manufacturer,
                agg.storeID,
                agg.chainID,
                D.brandName,
                S.storeName,
                agg.orderCount,
                agg.grossSales,
                B.plutusTerminalID,
                D.companyName,
                D.industry,
                D.packageID,

            // $kotVoidArray[$count]["invoiceNumber"]      = $dataArray["kotVoidDetails"][$i]["invoiceNumber"];
            $kotVoidArray[$count]["productValue"]      = $dataArray["kotVoidDetails"][$i]["productValue"];

            $count++;
        }

        DB::transaction(function() use ($kotVoidArray, $kotDetailsTable,$chainKotDetailTable, $storeID)
        {
            for ($j = 0; $j < count($kotVoidArray); $j++) {
                try {
                DB::table($kotDetailsTable)->insert($kotVoidArray[$j]);
                $kotVoidArray[$j]["storeID"] = $storeID;
                DB::table($chainKotDetailTable)->insert($kotVoidArray[$j]);
                } catch (\Throwable $e) {
                    Log::error("Error while storing kot void detail. Store: ".$storeID. " detail ". json_encode($kotVoidArray[$j]));
					// Send to Sentry
					try {
						Log::info("Sending error to sentry");
						if (env("APP_ENV") == "production") {
							app('sentry')->captureException($e);
						}
					} catch (\Throwable $th) {
						// 
					}
                }
            }
        });

        $responseArray["status"] = true;
        $responseArray["data"] = $kotVoidArray;
        return $responseArray;
    }


