        if (isset($nodeResponse['status']) && $nodeResponse['status'] == true) {
            try {
                // Update NectorSync = 1 for the invoice(s)
                DB::table($invoiceSummaryTable)->where('orderID', $orderID)->update(['NectorSync' => 1]);

                // For void orders, also update the refund order
                if ($reqType == "VOID" && !empty($refundOrderID)) {
                    DB::table($invoiceSummaryTable)->where('orderID', $refundOrderID)->update(['NectorSync' => 1]);
                }
            } catch (\Exception $e) {
                Log::warning("Failed to update NectorSync flag", [
                    'chainID' => $chainID,
                    'orderID' => $orderID,
                    'refundOrderID' => $refundOrderID,
                    'error' => $e->getMessage()
                ]);
            }
        }

        $status["status"] = true;
        $status["message"] = "Nector data sent successfully";
        $status["response"] = $nodeResponse;
        Log::info("Nector invoice response", [
            'chainID' => $chainID,
            'storeID' => $storeID,
            'orderID' => $orderID,
            'reqType' => $reqType,
            'nectorArray' => $nectorArray,
            'nodeResponse' => $nodeResponse
        ]);
        return $status;

    } catch (\Exception $e) {
        $status["status"] = false;
        $status["message"] = "Error in postDataToNector (invoice): " . $e->getMessage();
        Log::error("Error in postDataToNector (invoice): " . $e->getMessage());
        return $status;
    }
}

