    /**
     * Copy payment mappings to a single destination store
     * 
     * @param int $destStoreID Destination store ID
     * @param array $sourcePaymentMappings Payment mappings to copy
     * @return array Result with success status and counts
     */
    private function copyToSingleStore($destStoreID, $sourcePaymentMappings)
    {
        $paymentSettingsTable = Constants::getTableName($destStoreID, "paymentSettings");
        $addedCount = 0;
        $updatedCount = 0;

        foreach ($sourcePaymentMappings as $mapping) {
            // Check if mapping already exists
            $existing = DB::table($paymentSettingsTable)
                ->where('paymentTypeID', $mapping['paymentTypeID'])
                ->first();

            $mappingData = [
                'paymentTypeID' => $mapping['paymentTypeID'],
                'isSystemIntegrated' => $mapping['isSystemIntegrated'] ?? 0,
                'isActive' => 1,
                'printName' => $mapping['printName'] ?? null
            ];

            if ($existing) {
                // Update existing mapping
                DB::table($paymentSettingsTable)
                    ->where('paymentTypeID', $mapping['paymentTypeID'])
                    ->update($mappingData);
                $updatedCount++;
            } else {
                // Insert new mapping
                DB::table($paymentSettingsTable)->insert($mappingData);
                $addedCount++;
            }
        }

        return [
            'success' => true,
            'added' => $addedCount,
            'updated' => $updatedCount
        ];
    }
