 44	                ];
 45	            }
 46	
 47	            // Validate all destination stores
 48	            foreach ($destinationStores as $destStoreID) {
 49	                $destValidation = $this->validateStore($destStoreID, $chainID);
 50	                if (!$destValidation['valid']) {
 51	                    return [
 52	                        'status' => false,
 53	                        'message' => "Invalid destination store {$destStoreID}: " . $destValidation['message']
