125	    private function getDestinationStores($chainID, $sourceStoreID, $destinationStoreIDs)
126	    {
127	        if ($destinationStoreIDs === "ALL" || (is_string($destinationStoreIDs) && strtoupper($destinationStoreIDs) === "ALL")) {
128	            // Get all stores in the chain except the source store
129	            $listOfStoresTable = Constants::getGlobalTableName("listOfStores");
130	            
131	            $stores = DB::table($listOfStoresTable)
132	                ->where('chainID', $chainID)
133	                ->where('isActive', 1)
134	                ->where('storeID', '!=', $sourceStoreID)
135	                ->pluck('storeID')
136	                ->toArray();
137	
138	            return $stores;
139	        }
140	
141	        // Ensure it's an array
142	        if (!is_array($destinationStoreIDs)) {
143	            $destinationStoreIDs = [$destinationStoreIDs];
144	        }
145	
146	        // Remove source store if it's in the list
147	        $destinationStoreIDs = array_filter($destinationStoreIDs, function($id) use ($sourceStoreID) {
148	            return $id != $sourceStoreID;
149	        });
150	
151	        return array_values($destinationStoreIDs);
152	    }
