public static function getSalesByPayment($data, $chainID){

    $fromDate = $data["fromDate"];
    $toDate = $data["toDate"];

    if (empty($fromDate)) {
        $fromDate = date("Y-m-d");
    }

    if (empty($toDate)) {
        $toDate = date("Y-m-d");
    }

    if (isset($data['deviceRange'])) {
        $deviceRange = $data['deviceRange'];
        if ($deviceRange != 'ALL' && $deviceRange != '') {
            $deviceRangeCondition = "AND C.deviceID IN ($deviceRange)";
        }else{
            $deviceRangeCondition = NULL;    
        }

    }else{
        $deviceRangeCondition = NULL;
    }

    $orderList = array();
    $dateRangeArray = self::createDateRangeArray($fromDate, $toDate);

