    if (intval($storeID) == 0 && $storeID != "ALL") {
        $status["status"] = false;
        $status["message"] = "Invalid storeID";

        return $status;
    }
    $userID = $data["userID"];

    if (intval($userID) == 0) {
        $status["status"] = false;
        $status["message"] = "Invalid userID";

        return $status;
