    $userStoreMapTable = Constants::getGlobalTableName("userStoreMap");
    $listOfStoresTable = Constants::getGlobalTableName("listOfStores");

    $allPaymentModes = getPaymentModes($storeID, 0, $fromDate, $toDate);
    $paymentModes = $allPaymentModes["modes"];
    $allValues = $allPaymentModes["allValues"];

    if ($data["storeID"] == "ALL") {
        $orderPaymentTable = Constants::getChainTableName($chainID, "orderPayments");
        $orderSummaryTable = Constants::getChainTableName($chainID,"orderSummary");
        if ($deviceRangeCondition != NULL) {
            $deviceQuery = " INNER JOIN $orderSummaryTable AS C ON A.orderID = C.orderID";
        } else {
            $deviceQuery = "";
        }
        $query = "SELECT DISTINCT DATE_FORMAT(A.paymentPosDate,'%d %b, %Y') AS orderDate,
            $paymentModes
            A.storeID, B.storeName, CONCAT(A.storeID,'-',DATE(A.paymentPosDate)) AS storeDateKey  
            FROM $orderPaymentTable AS A 
            INNER JOIN $listOfStoresTable AS B ON A.storeID = B.storeID
            $deviceQuery
            WHERE DATE(A.paymentPosDate) >= ? AND DATE(A.paymentPosDate) <= ? 
            AND A.storeID IN (SELECT DISTINCT storeID FROM $userStoreMapTable WHERE userID = $userID ) 
