 10	/**
 11	 * Service class for managing payment method mappings across stores
 12	 * 
 13	 * Handles copying payment settings from a source store to destination stores
 14	 * within the same chain, with proper validation and transaction management.
 15	 */
 16	class PaymentMappingService
 17	{
 18	    /**
 19	     * Copy payment method mappings from source store to destination stores
 20	     * 
 21	     * @param int $chainID Chain ID
 22	     * @param int $sourceStoreID Source store ID to copy from
 23	     * @param mixed $destinationStoreIDs Array of store IDs or "ALL" string
 24	     * @return array Response with status and details
 25	     */
 26	    public function copyPaymentMappings($chainID, $sourceStoreID, $destinationStoreIDs)
 27	    {
 28	        try {
 29	            // Validate source store
 30	            $sourceValidation = $this->validateStore($sourceStoreID, $chainID);
 31	            if (!$sourceValidation['valid']) {
 32	                return [
 33	                    'status' => false,
 34	                    'message' => $sourceValidation['message']
 35	                ];
 36	            }
 37	
 38	            // Get destination store IDs
 39	            $destinationStores = $this->getDestinationStores($chainID, $sourceStoreID, $destinationStoreIDs);
 40	            if (empty($destinationStores)) {
 41	                return [
 42	                    'status' => false,
 43	                    'message' => 'No valid destination stores found'
 44	                ];
 45	            }
 46	
 47	            // Validate all destination stores
 48	            foreach ($destinationStores as $destStoreID) {
 49	                $destValidation = $this->validateStore($destStoreID, $chainID);
 50	                if (!$destValidation['valid']) {
 51	                    return [
 52	                        'status' => false,
 53	                        'message' => "Invalid destination store {$destStoreID}: " . $destValidation['message']
 54	                    ];
 55	                }
 56	            }
 57	
 58	            // Get payment mappings from source store
 59	            $sourcePaymentMappings = $this->getStorePaymentMappings($sourceStoreID);
 60	            if (empty($sourcePaymentMappings)) {
 61	                return [
 62	                    'status' => false,
 63	                    'message' => 'No payment mappings found in source store'
 64	                ];
 65	            }
 66	
 67	            // Copy mappings to destination stores
 68	            $result = $this->copyMappingsToStores($sourceStoreID, $destinationStores, $sourcePaymentMappings);
 69	
 70	            return $result;
 71	
 72	        } catch (Exception $e) {
 73	            Log::error('Error copying payment mappings', [
 74	                'chainID' => $chainID,
 75	                'sourceStoreID' => $sourceStoreID,
 76	                'error' => $e->getMessage(),
 77	                'trace' => $e->getTraceAsString()
 78	            ]);
 79	
 80	            return [
 81	                'status' => false,
 82	                'message' => 'An error occurred while copying payment mappings: ' . $e->getMessage()
 83	            ];
 84	        }
 85	    }
