 91	     * @param int $chainID Chain ID
 92	     * @return array Validation result
 93	     */
 94	    private function validateStore($storeID, $chainID)
 95	    {
 96	        $listOfStoresTable = Constants::getGlobalTableName("listOfStores");
 97	
 98	        $store = DB::table($listOfStoresTable)
 99	            ->where('storeID', $storeID)
100	            ->where('chainID', $chainID)
